  1415→					if (Object.isFrozen(thenables)) {
  1416→						throw new Error('waitUntil can NOT be called asynchronous');
  1417→					}
  1418→					if (promiseJoin) {
  1419→						p = promiseJoin(p, listener);
  1420→					}
  1421→					thenables.push(p);
  1422→				}
  1423→			};
